+        Self::default()
+    }
+
+    /// Set the ETag generation mode.
+    #[must_use]
+    pub fn mode(mut self, mode: ETagMode) -> Self {
+        self.mode = mode;
+        self
+    }
+
+    /// Enable weak ETags.
+    #[must_use]
+    pub fn weak(mut self, weak: bool) -> Self {
+        self.weak = weak;
+        self
+    }
+
+    /// Set minimum body size for ETag generation.
+    #[must_use]
+    pub fn min_size(mut self, size: usize) -> Self {
+        self.min_size = size;
+        self
+    }
+}
